chrome.tabs.query({}, function(tabs) {
  var currentTabId = tabs.filter(t => t.active && t.window === chrome.windows.getCurrent().id)[0];
  // Get current window's tabs
  chrome.windows.getCurrent(function(window) {
    var currentTab = window.tabs.find(t => t.active);
    var tabsToClose = window.tabs.filter(t => t.id !== currentTab.id);
    var tabIds = tabsToClose.map(t => t.id);
    if (tabIds.length > 0) {
      chrome.tabs.remove(tabIds, function() {
        console.log('Closed ' + tabIds.length + ' tabs');
      });
    } else {
      console.log('No other tabs to close');
    }
  });
});
